import { color as d3color } from 'd3-color';

import { getColorByContrast } from '../../../utils/color-contrast.js';
import { getCanvasColor } from '../../canvas/utils/canvas-color.js';

const getSafeHexColor = (colorString: string): string => {
  const d3ColorResult = d3color(colorString);
  if (d3ColorResult === null) {
    const fallbackColor = d3color('#000000');
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    return fallbackColor!.formatHex();
  }
  return d3ColorResult.formatHex();
};

export const getContentAndBackgroundColor = (
  calculatedColor: string,
  applyThresholdBackground: boolean = false,
) => {
  const sanitizedColor = getCanvasColor(calculatedColor);

  return applyThresholdBackground
    ? {
        backgroundColor: calculatedColor,
        contentColor: getColorByContrast(getSafeHexColor(sanitizedColor)),
      }
    : { backgroundColor: 'inherit', contentColor: calculatedColor };
};
